<?php
namespace Tests\Unit;
use App\Services\Trading\PositionManagementReviewPlanService;use Tests\TestCase;
class PositionManagementReviewPlanServiceTest extends TestCase
{protected function candidate($type='protection_breach_review',$condition='stop_reference_breached'):array{return ['schema_version'=>'trading_position_management_candidate_v1','status'=>'policy_hypothesis','candidate_id'=>str_repeat('a',64),'candidate_type'=>$type,'position_id'=>'position-bumi-1','ticker'=>'BUMI','position_side'=>'long','condition'=>$condition,'policy_id'=>'policy-1','policy_rule_id'=>'rule-1'];}protected function risk($status='condition_risk_observed'):array{return ['schema_version'=>'trading_position_management_risk_v1','status'=>$status,'position_id'=>'position-bumi-1','candidate_id'=>str_repeat('a',64),'candidate_type'=>'protection_breach_review','condition'=>'stop_reference_breached','metrics'=>['stop_breach_depth_per_unit'=>1]];}protected function policy():array{return ['policy_id'=>'policy-1'];}
public function test_not_required_unavailable_and_ready():void{$svc=new PositionManagementReviewPlanService();$this->assertSame('not_required',$svc->build(['decision_scope'=>'entry_evaluation'])['status']);$this->assertSame('unavailable',$svc->build(['decision_scope'=>'position_management'])['status']);$r=$svc->build(['decision_scope'=>'position_management','management_candidate'=>$this->candidate(),'management_risk'=>$this->risk(),'policy_evaluation'=>$this->policy()]);$this->assertSame('review_context_ready',$r['status']);$this->assertContains('confirm_current_market_observation',$r['required_evidence']);$this->assertContains('management_action_policy',$r['unavailable_evidence']);$this->assertSame('not_implemented',$r['action_plan']['status']);$this->assertNull($r['action_plan']['action']);$this->assertNull($r['action_plan']['quantity']);$this->assertNull($r['action_plan']['new_stop']);$this->assertNull($r['action_plan']['new_target']);$this->assertSame('not_implemented',$r['execution']['status']);}
public function test_target_missing_stale_and_validation():void{$svc=new PositionManagementReviewPlanService();$target=$svc->build(['decision_scope'=>'position_management','management_candidate'=>$this->candidate('target_reached_review','target_reference_reached'),'management_risk'=>array_replace($this->risk(),['condition'=>'target_reference_reached','candidate_type'=>'target_reached_review']),'policy_evaluation'=>$this->policy()]);$this->assertSame('review_context_ready',$target['status']);$missing=$svc->build(['decision_scope'=>'position_management','management_candidate'=>$this->candidate('protection_missing_review','protection_reference_missing'),'management_risk'=>array_replace($this->risk('partial'),['condition'=>'protection_reference_missing','candidate_type'=>'protection_missing_review']),'policy_evaluation'=>$this->policy()]);$this->assertSame('review_context_ready',$missing['status']);$this->assertContains('complete_management_risk',$missing['unavailable_evidence']);$stale=$svc->build(['decision_scope'=>'position_management','management_candidate'=>$this->candidate('stale_observation_review','market_observation_stale'),'management_risk'=>array_replace($this->risk('blocked'),['condition'=>'market_observation_stale','candidate_type'=>'stale_observation_review']),'policy_evaluation'=>$this->policy()]);$this->assertSame('unavailable',$stale['status']);$target['action_plan']['action']='SELL';$this->expectException(\InvalidArgumentException::class);$svc->validateReviewPlan($target);}}
